+#ifndef COIN_D4_LIDAR__COIN_D4_HANDLER_HPP_
+#define COIN_D4_LIDAR__COIN_D4_HANDLER_HPP_
+
+#include <atomic>
+#include <memory>
+#include <string>
+#include <thread>
+
+#include "coin_d4_driver/lidar_sdk/lidar_data_processing.h"
