+result_t Lidar_Data_Processing::sendData(const uint8_t *data, size_t size)
+{
+
+  if (data == NULL || size == 0)
+  {
+    return RESULT_FAIL;
+  }
+
+  size_t r;
+
+  while (size)
+  {
+    r = serial_port_->write_data(data, size);
+
+    if (r < 1)
+    {
+      return RESULT_FAIL;
+    }
+
+    size -= r;
+    data += r;
+  }
+  return RESULT_OK;
+}
