+void Serial_Port::set_databits(termios *tio, bytesize_t databits) {
+  tio->c_cflag &= ~CSIZE;
+
+  switch (databits) {
+    case fivebits:
+      tio->c_cflag |= CS5;
+      break;
+
+    case sixbits:
+      tio->c_cflag |= CS6;
+      break;
+
+    case sevenbits:
+      tio->c_cflag |= CS7;
+      break;
+
+    case eightbits:
+      tio->c_cflag |= CS8;
+      break;
+
+    default:
+      tio->c_cflag |= CS8;
+      break;
+  }
+}
+
+void Serial_Port::set_parity(termios *tio,parity_t parity) {
+  tio->c_iflag &= ~(PARMRK | INPCK);
+  tio->c_iflag |= IGNPAR;
+
+  switch (parity) {
+
+#ifdef CMSPAR
+
+    case parity_space:
+      tio->c_cflag &= ~PARODD;
+      tio->c_cflag |= PARENB | CMSPAR;
+      break;
+
+    case parity_mark:
+      tio->c_cflag |= PARENB | CMSPAR | PARODD;
+      break;
+#endif
+
+    case parity_none:
+      tio->c_cflag &= ~PARENB;
+      break;
+
+    case parity_even:
+      tio->c_cflag &= ~PARODD;
+      tio->c_cflag |= PARENB;
+      break;
+
+    case parity_odd:
+      tio->c_cflag |= PARENB | PARODD;
+      break;
+
+    default:
+      tio->c_cflag |= PARENB;
+      tio->c_iflag |= PARMRK | INPCK;
+      tio->c_iflag &= ~IGNPAR;
+      break;
+  }
+}
+
+void Serial_Port::set_stopbits(termios *tio, stopbits_t stopbits) {
+  switch (stopbits) {
+    case stopbits_one:
+      tio->c_cflag &= ~CSTOPB;
+      break;
+
+    case stopbits_two:
+      tio->c_cflag |= CSTOPB;
+      break;
+
+    default:
+      tio->c_cflag &= ~CSTOPB;
+      break;
+  }
+}
+
+void Serial_Port::set_flowcontrol(termios *tio,flowcontrol_t flowcontrol) {
+  switch (flowcontrol) {
+    case flowcontrol_none:
+      tio->c_cflag &= ~CRTSCTS;
+      tio->c_iflag &= ~(IXON | IXOFF | IXANY);
+      break;
+
+    case flowcontrol_hardware:
+      tio->c_cflag |= CRTSCTS;
+      tio->c_iflag &= ~(IXON | IXOFF | IXANY);
+      break;
+
+    case flowcontrol_software:
+      tio->c_cflag &= ~CRTSCTS;
+      tio->c_iflag |= IXON | IXOFF | IXANY;
+      break;
+
+    default:
+      tio->c_cflag &= ~CRTSCTS;
+      tio->c_iflag &= ~(IXON | IXOFF | IXANY);
+      break;
+  }
+}
